const json = $input.item.json;
const f = json.fields || json.Felder || {};

const thema   = f.field_1  || f.Field_1  || '(kein Thema)';
const caption = f.field_10 || f.Field_10 || '';
const bildUrl = String(f.field_8 || f.Field_8 || '').trim();
const itemId  = parseInt(String(json.AUSWEIS || json.id || 0).trim(), 10);

// Bild vorhanden wenn: nicht leer, nicht '0', nicht numerisch 0
const hatBild = bildUrl && bildUrl !== '0' && !/^0+$/.test(bildUrl);

return {
  json: {
    ...json,
    thema:              thema,
    caption:            caption,
    bild_url:           hatBild ? bildUrl : '',
    hat_bild:           hatBild,
    sharepoint_item_id: itemId,
  }
};

// PFAD B: Manuelles Bild direkt verwenden
const json = $input.item.json;
return {
  json: {
    final_bild_url:      json.bild_url,
    thema:               json.thema,
    sharepoint_item_id:  json.sharepoint_item_id,
    bild_quelle:         'manuell',
    generated_at:        new Date().toISOString()
  }
};

// PFAD A: HTML-Template für Physio Fuchs generieren
const json = $input.item.json;
const thema = json.thema || 'Physiotherapie';

// Physio Fuchs Farben (aus Canva Vorlage)
const gruen    = '#5a7a4a';  // Dunkelgrün
const hellgruen= '#6e9b5e';  // Hellgrün für Akzent
const creme    = '#f2ede4';  // Cremehintergrund
const braun    = '#7a5c3a';  // Warmbraun
const weiss    = '#ffffff';

// HTML-Template (1080x1920px = Instagram Story Format)
const html = `
<div style="
  width:1080px;
  height:1920px;
  background:${creme};
  font-family:'Georgia',serif;
  position:relative;
  overflow:hidden;
  display:flex;
  flex-direction:column;
  align-items:center;
  justify-content:center;
">

  <!-- Obere Balken -->
  <div style="
    position:absolute;top:0;left:0;right:0;height:90px;
    background:${gruen};
  "></div>

  <!-- Dekoratives Blatt oben rechts -->
  <div style="
    position:absolute;top:30px;right:60px;
    width:280px;height:220px;
    opacity:0.25;
    background:${hellgruen};
    border-radius:50% 0 50% 0;
    transform:rotate(20deg);
  "></div>
  <div style="
    position:absolute;top:60px;right:200px;
    width:180px;height:140px;
    opacity:0.15;
    background:${hellgruen};
    border-radius:50% 0 50% 0;
    transform:rotate(20deg);
  "></div>

  <!-- Grüner Hauptbanner mit Thema -->
  <div style="
    background:${gruen};
    padding:55px 70px;
    text-align:center;
    width:920px;
    margin-bottom:220px;
    position:relative;
    z-index:2;
  ">
    <!-- Kleines Dekorationsblatt im Banner -->
    <div style="
      position:absolute;top:-20px;right:20px;
      width:120px;height:100px;
      opacity:0.3;
      background:${hellgruen};
      border-radius:50% 0 50% 0;
      transform:rotate(15deg);
    "></div>
    <div style="
      color:${weiss};
      font-size:${thema.length > 20 ? '68px' : '82px'};
      font-weight:bold;
      line-height:1.2;
      letter-spacing:1px;
      position:relative;
      z-index:3;
    ">${thema}</div>
  </div>

  <!-- Dekoratives Blatt unten links -->
  <div style="
    position:absolute;bottom:200px;left:40px;
    width:200px;height:160px;
    opacity:0.2;
    background:${gruen};
    border-radius:50% 0 50% 0;
    transform:rotate(200deg);
  "></div>

  <!-- Logo-Bereich -->
  <div style="
    position:absolute;
    bottom:140px;
    left:50%;
    transform:translateX(-50%);
    background:${weiss};
    padding:28px 70px;
    border-radius:4px;
    text-align:center;
    box-shadow:0 4px 20px rgba(0,0,0,0.12);
    white-space:nowrap;
  ">
    <div style="
      font-size:38px;
      letter-spacing:10px;
      color:${gruen};
      font-weight:bold;
      font-family:'Georgia',serif;
    ">PHYSIO FUCHS</div>
  </div>

  <!-- Unterer Balken -->
  <div style="
    position:absolute;bottom:0;left:0;right:0;height:90px;
    background:${gruen};
  "></div>

  <!-- Dekorationsblatt unterer Balken -->
  <div style="
    position:absolute;bottom:50px;right:80px;
    width:160px;height:120px;
    opacity:0.25;
    background:${hellgruen};
    border-radius:50% 0 50% 0;
    transform:rotate(20deg);
  "></div>

</div>
`;

// hcti.io API Payload
const userId = $env.HCTI_USER_ID || '';
const apiKey = $env.HCTI_API_KEY || '';
const authHeader = 'Basic ' + Buffer.from(`${userId}:${apiKey}`).toString('base64');

return {
  json: {
    // hcti.io Request
    html: html,
    viewport_width: 1080,
    viewport_height: 1920,
    google_fonts: 'Georgia',
    // Auth Header für nächsten Node
    _auth_header: authHeader,
    // Metadaten durchreichen
    _meta: {
      thema: thema,
      sharepoint_item_id: json.sharepoint_item_id
    }
  }
};

const response = $input.item.json;
const prev = $('HTML Template generieren').item.json._meta;

// hcti.io gibt {url: 'https://hcti.io/v1/image/UUID.png'} zurück
const imageUrl = response.url || response.image_url || '';

if (!imageUrl) {
  throw new Error('Kein Bild-URL von hcti.io. Response: ' + JSON.stringify(response).substring(0, 300));
}

return {
  json: {
    final_bild_url:     imageUrl,
    thema:              prev?.thema || '',
    sharepoint_item_id: prev?.sharepoint_item_id || 0,
    bild_quelle:        'html',
    generated_at:       new Date().toISOString()
  }
};
